module RefModule(
  input CLK,
  input EN,
  input TE,
  input reset,
  output ENCLK
);reg obf_ENCLK_reg;

  always @(posedge CLK, posedge reset) begin
    if (reset) begin
      obf_ENCLK_reg <= 1'b0;
    end else if (EN && TE) begin
      obf_ENCLK_reg <= ~obf_ENCLK_reg;
    end
  end

  assign ENCLK = obf_ENCLK_reg;

endmodule
